import React, { useEffect, useRef, useState } from 'react';
import { Zap, Droplets, Wind, TreePine } from 'lucide-react';

const features = [
  { icon: Zap, label: 'Smart Energy Systems', desc: 'Solar integration and intelligent energy management to minimize consumption across all developments.' },
  { icon: Droplets, label: 'Water Conservation', desc: 'Advanced irrigation and recycling systems that preserve Oman\'s precious water resources.' },
  { icon: Wind, label: 'Climate-Responsive Design', desc: 'Architecture that works with the natural environment — passive cooling, natural light, cross ventilation.' },
  { icon: TreePine, label: 'Green Corridors', desc: 'Extensive landscaping with native flora creating biodiversity and natural cooling across all communities.' },
];

export default function Sustainability() {
  const [visible, setVisible] = useState(false);
  const ref = useRef();

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) setVisible(true); },
      { threshold: 0.1 }
    );
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, []);

  return (
    <section id="sustainability" ref={ref} style={{
      padding: '140px 0',
      background: 'var(--navy-deepest)',
      position: 'relative',
      overflow: 'hidden',
    }}>
      {/* Large circle background */}
      <div style={{
        position: 'absolute',
        left: '-200px', top: '50%',
        transform: 'translateY(-50%)',
        width: '600px', height: '600px',
        borderRadius: '50%',
        border: '1px solid rgba(201,169,110,0.06)',
        pointerEvents: 'none',
      }} />
      <div style={{
        position: 'absolute',
        left: '-100px', top: '50%',
        transform: 'translateY(-50%)',
        width: '400px', height: '400px',
        borderRadius: '50%',
        border: '1px solid rgba(201,169,110,0.1)',
        pointerEvents: 'none',
      }} />

      <div className="container">
        <div style={{
          display: 'grid',
          gridTemplateColumns: '1fr 1fr',
          gap: '100px',
          alignItems: 'center',
        }}>
          {/* Left */}
          <div>
            <div style={{
              display: 'inline-flex', alignItems: 'center', gap: '12px',
              marginBottom: '24px',
              opacity: visible ? 1 : 0,
              transform: visible ? 'translateY(0)' : 'translateY(20px)',
              transition: 'all 0.7s ease',
            }}>
              <div style={{ width: '32px', height: '1px', background: 'var(--gold)' }} />
              <span style={{ fontFamily: 'var(--font-body)', fontSize: '11px', letterSpacing: '0.3em', color: 'var(--gold)', textTransform: 'uppercase', fontWeight: 500 }}>Sustainability</span>
            </div>

            <h2 style={{
              fontFamily: 'var(--font-display)',
              fontSize: 'clamp(44px, 5vw, 72px)',
              fontWeight: 300,
              lineHeight: 1.05,
              color: 'var(--white)',
              letterSpacing: '-0.02em',
              marginBottom: '32px',
              opacity: visible ? 1 : 0,
              transform: visible ? 'translateY(0)' : 'translateY(30px)',
              transition: 'all 0.8s var(--ease-out) 0.2s',
            }}>
              Building for<br />
              <em style={{ color: 'var(--gold)', fontStyle: 'italic' }}>Tomorrow</em>
            </h2>

            <p style={{
              fontFamily: 'var(--font-body)',
              fontSize: '16px',
              fontWeight: 300,
              lineHeight: 1.9,
              color: 'var(--white-70)',
              marginBottom: '48px',
              opacity: visible ? 1 : 0,
              transition: 'opacity 0.8s ease 0.4s',
            }}>
              Sustainability is not a checkbox at ADVA — it is the foundation of every decision we make. From land selection to material sourcing to smart infrastructure, we design with the future in mind.
            </p>

            {/* Progress bars */}
            {[
              { label: 'Green Space Allocation', pct: 68 },
              { label: 'Energy Efficiency Rating', pct: 85 },
              { label: 'Sustainable Materials', pct: 72 },
            ].map((item, i) => (
              <div key={i} style={{
                marginBottom: '24px',
                opacity: visible ? 1 : 0,
                transition: `opacity 0.8s ease ${0.5 + i * 0.15}s`,
              }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                  <span style={{ fontFamily: 'var(--font-body)', fontSize: '12px', letterSpacing: '0.1em', color: 'var(--white-70)' }}>{item.label}</span>
                  <span style={{ fontFamily: 'var(--font-body)', fontSize: '12px', color: 'var(--gold)', fontWeight: 500 }}>{item.pct}%</span>
                </div>
                <div style={{ height: '2px', background: 'rgba(255,255,255,0.1)' }}>
                  <div style={{
                    height: '100%',
                    width: visible ? `${item.pct}%` : '0%',
                    background: 'linear-gradient(90deg, var(--gold), var(--gold-light))',
                    transition: `width 1.2s var(--ease-out) ${0.7 + i * 0.15}s`,
                  }} />
                </div>
              </div>
            ))}
          </div>

          {/* Right — Features grid */}
          <div style={{
            display: 'grid',
            gridTemplateColumns: '1fr 1fr',
            gap: '2px',
          }}>
            {features.map((feat, i) => {
              const Icon = feat.icon;
              return (
                <div key={i} style={{
                  padding: '40px 32px',
                  background: 'rgba(255,255,255,0.03)',
                  border: '1px solid rgba(201,169,110,0.1)',
                  opacity: visible ? 1 : 0,
                  transform: visible ? 'translateY(0)' : 'translateY(30px)',
                  transition: `all 0.8s var(--ease-out) ${0.3 + i * 0.1}s`,
                }}>
                  <div style={{
                    width: '44px', height: '44px',
                    borderRadius: '50%',
                    border: '1px solid rgba(201,169,110,0.3)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    marginBottom: '24px',
                  }}>
                    <Icon size={18} color="var(--gold)" />
                  </div>
                  <h4 style={{
                    fontFamily: 'var(--font-body)',
                    fontSize: '13px',
                    fontWeight: 600,
                    color: 'var(--white)',
                    letterSpacing: '0.05em',
                    marginBottom: '12px',
                    textTransform: 'uppercase',
                  }}>{feat.label}</h4>
                  <p style={{
                    fontFamily: 'var(--font-body)',
                    fontSize: '13px',
                    fontWeight: 300,
                    lineHeight: 1.7,
                    color: 'var(--white-70)',
                  }}>{feat.desc}</p>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      <style>{`
        @media (max-width: 900px) {
          #sustainability .container > div { grid-template-columns: 1fr !important; gap: 60px !important; }
        }
      `}</style>
    </section>
  );
}
